## Current behavior

```typescript
import { Toast } from '@base-ui-components/react/toast';
// toast.ts
export const toastManager = Toast.createToastManager();

// Toast.tsx
import { toastManager } from './toast.ts';
export const ToastProvider = () => (
  <Toast.Provider toastManager={toastManager}>
    {/* ... */}
  </Toast.Provider>
);
```

